SourceCode.Declaration:
/// <summary>
/// Prodcut Color import
/// </summary>
public class ETG_Acu_EcoResProdMasterColorImport extends ETG_Acu_DataImportBase
{
}

Method.Source:
public static void main(Args args)
{
    ETG_Acu_EcoResProdMasterColorImport  prodColorImport;

    prodColorImport = ETG_Acu_EcoResProdMasterColorImport::construct();

    if (prodColorImport.prompt())
    {
        prodColorImport.runOperation();
    }
}

public static ETG_Acu_EcoResProdMasterColorImport construct()
{
    return new ETG_Acu_EcoResProdMasterColorImport();
}

/// <summary>
/// Describes whether the class is designed for execution in a new session.
/// </summary>
/// <returns>
/// true if the class is designed for execution the operation in a new session; otherwise, false.
/// </returns>
protected boolean canRunInNewSession()
{
    return false;
}

protected void processData(container _con)
{
    EcoResProductMasterColorEntity      prodColor;
    EcoResProductDisplayProductNumber   prodNum;
    EcoResColorName                     colorName;

    prodNum     = conpeek(_con, 1);
    colorName   = conpeek(_con, 2);

    select firstonly prodColor
        where prodColor.ProductMasterNumber == prodNum
            && prodColor.ProductColorId     == colorName;

    if (!prodColor)
    {
        prodColor.initValue();
        prodColor.ProductMasterNumber   = prodNum;
        prodColor.ProductColorId        = colorName;
        prodColor.insert();
    }
}

/// <summary>
/// Import colors
/// </summary>
/// <returns>Caption</returns>
public ClassDescription caption()
{
    ClassDescription ret;

    ret = "@ETG_ENG_Labels:ImpProdColor";

    return ret;
}
